  "Benin":{ flag:"🇧🇯", capital:"Porto-Novo", population:"13.0M", language:"French", sport:"Football", fact:"The Kingdom of Dahomey in what is now Benin fielded an elite all-female military corps called the Agojie (Dahomey Amazons) who were active warriors from the 17th through the 19th century." },
  "Bhutan":{ flag:"🇧🇹", capital:"Thimphu", population:"760,000", language:"Dzongkha", sport:"Archery", fact:"Bhutan is the only country in the world that measures national progress using Gross National Happiness instead of GDP, a policy enshrined in its constitution." },
  "Bosnia and Herzegovina":{ flag:"🇧🇦", capital:"Sarajevo", population:"3.2M", language:"Bosnian, Croatian, Serbian", sport:"Football", fact:"Sarajevo hosted the 1984 Winter Olympics and is one of the few cities to have been besieged in modern Europe — the Siege of Sarajevo (1992–96) was the longest siege of a capital city in the history of modern warfare." },
  "Botswana":{ flag:"🇧🇼", capital:"Gaborone", population:"2.6M", language:"English, Setswana", sport:"Football / Athletics", fact:"Botswana went from one of the world's poorest countries at independence in 1966 to an upper-middle-income economy, largely through transparent diamond revenues — the Jwaneng mine is the richest diamond mine on Earth by value." },
  "Brunei":{ flag:"🇧🇳", capital:"Bandar Seri Begawan", population:"440,000", language:"Malay", sport:"Football / Badminton", fact:"Brunei's Sultan Hassanal Bolkiah owns one of the world's largest private car collections, exceeding 7,000 vehicles — among them hundreds of Rolls-Royces and custom-built Ferraris." },
  "Burkina Faso":{ flag:"🇧🇫", capital:"Ouagadougou", population:"22.1M", language:"French", sport:"Football", fact:"Burkina Faso means 'Land of Incorruptible People' in both Mooré and Dioula — the name was coined in 1984 by revolutionary leader Thomas Sankara." },
  "Burundi":{ flag:"🇧🇮", capital:"Gitega", population:"12.6M", language:"Kirundi, French, English", sport:"Football / Athletics", fact:"The Royal Drummers of Burundi, who perform on intore ceremonial drums, are UNESCO-listed and have played for royalty for centuries — their performances last up to 72 hours." },
